// Let's find solutions to cos(x) = x
// First, let's plot the two functions to visualize where they intersect
// We need to find where cos(x) - x = 0

import * as math from 'mathjs';

// Create a range of x values to examine
const xValues = [];
const cosValues = [];
const xLineValues = [];
const diffValues = [];

// Create data points for plotting
for (let x = -3; x <= 3; x += 0.01) {
  xValues.push(x);
  cosValues.push(Math.cos(x));
  xLineValues.push(x);
  diffValues.push(Math.cos(x) - x);
}

// Find approximate intersections using numerical method
console.log("Looking for where cos(x) - x = 0 (intersections of cos(x) and x):");

// Function to find sign changes in the difference array
function findZeroCrossings(xVals, diffVals) {
  const crossings = [];
  for (let i = 0; i < diffVals.length - 1; i++) {
    if (diffVals[i] * diffVals[i + 1] <= 0) {
      // Linear interpolation to find a more precise x value
      const x0 = xVals[i];
      const x1 = xVals[i + 1];
      const y0 = diffVals[i];
      const y1 = diffVals[i + 1];

      // Avoid division by zero
      if (y0 !== y1) {
        const xIntercept = x0 - y0 * (x1 - x0) / (y1 - y0);
        crossings.push(xIntercept);
      } else if (y0 === 0) {
        crossings.push(x0);
      }
    }
  }
  return crossings;
}

const solutions = findZeroCrossings(xValues, diffValues);
console.log("Approximate solutions (where cos(x) = x):", solutions);

// Verify the solutions
for (const sol of solutions) {
  console.log(`At x = ${sol.toFixed(6)}: cos(${sol.toFixed(6)}) = ${Math.cos(sol).toFixed(6)}, difference = ${(Math.cos(sol) - sol).toFixed(10)}`);
}

// Let's try to find a more accurate solution using Newton's method
function newtonMethod(f, df, x0, tolerance = 1e-10, maxIterations = 100) {
  let x = x0;
  let iteration = 0;

  while (iteration < maxIterations) {
    const fx = f(x);
    if (Math.abs(fx) < tolerance) {
      return x;
    }

    const dfx = df(x);
    if (dfx === 0) {
      console.log("Derivative is zero. Newton's method fails.");
      return null;
    }

    const xNew = x - fx / dfx;
    if (Math.abs(xNew - x) < tolerance) {
      return xNew;
    }

    x = xNew;
    iteration++;
  }

  console.log(`Newton's method did not converge after ${maxIterations} iterations.`);
  return x;
}

// Define our function and its derivative
const f = x => Math.cos(x) - x;
const df = x => -Math.sin(x) - 1;

// Use our approximate solution as starting point
const accurateSolution = newtonMethod(f, df, solutions[0]);
console.log(`More accurate solution using Newton's method: x = ${accurateSolution.toFixed(15)}`);
console.log(`At x = ${accurateSolution.toFixed(15)}: cos(x) = ${Math.cos(accurateSolution).toFixed(15)}`);
console.log(`Difference: ${(Math.cos(accurateSolution) - accurateSolution).toFixed(15)}`);

